#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

#define TABLE_SIZE 262144  // power of two > 2*MAXN

typedef struct { long long key; int cnt; } Entry;
static Entry table[TABLE_SIZE];
static int used[TABLE_SIZE];
static int curMark = 1;

static unsigned int hash_ll(long long x) {
    return (unsigned int)((x ^ (x >> 33)) * 0x9e3779b1u);
}

static void clearTable() {
    curMark++;
    if (curMark == 0) { // overflow guard
        for (int i = 0; i < TABLE_SIZE; ++i) used[i] = 0;
        curMark = 1;
    }
}

static int *getPtr(long long key) {
    unsigned int h = hash_ll(key) & (TABLE_SIZE - 1);
    while (used[h] == curMark && table[h].key != key) {
        h = (h + 1) & (TABLE_SIZE - 1);
    }
    if (used[h] != curMark) {
        used[h] = curMark;
        table[h].key = key;
        table[h].cnt = 0;
    }
    return &table[h].cnt;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        clearTable();
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            if (x <= 31622) { // floor(sqrt(1e9))
                long long sq = x * x;
                int *p = getPtr(sq);
                ans += *p;
            }
            int *cnt = getPtr(x);
            (*cnt)++;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

