int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        map<long long, long long> freq; // TreeMap equivalent
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            long long x; cin >> x;
            if (x <= 31622) {
                long long sq = x * x;
                auto it = freq.find(sq);
                if (it != freq.end()) ans += it->second;
            }
            ++freq[x];
        }
        cout << ans << '\n';
    }
    return 0;
}

