import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        freq = {}
        ans = 0
        for _ in range(N):
            x = int(next(it))
            if x <= 31622:
                sq = x * x
                ans += freq.get(sq, 0)
            freq[x] = freq.get(x, 0) + 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

